data.value:
.page-header { 
    display: flex; 
    justify-content: space-between; 
    align-items: flex-start; 
    height: 100%; 
    background-color: White;
}

.header-titles { 
    display: flex; 
    flex-direction: column; 
    font-family: 'Segoe UI', sans-serif;
}

.page-title {
    font-size: 24px;
    font-weight: bold;
    color: #0F172A;
    margin-bottom: 3px;
}
.page-subtitle {
    font-size: 12px;
    color: #43474F;
}
